 6→package kotlinx.datetime.internal.format
 7→
 8→/**
 9→ * An append-only list of constituent formats. Can't be exposed directly due to the variance rules.
10→ */
11→internal class AppendableFormatStructure<T> {
12→    private val list: MutableList<NonConcatenatedFormatStructure<T>> = mutableListOf()
13→    fun build(): ConcatenatedFormatStructure<T> = ConcatenatedFormatStructure(list)
14→    fun add(format: FormatStructure<T>) {
15→        /** TODO: use the caches present in [CachedFormatStructure]. */
16→        when (format) {
17→            is NonConcatenatedFormatStructure -> list.add(format)
18→            is ConcatenatedFormatStructure -> format.formats.forEach { list.add(it) }
19→        }
20→    }
21→}
