internal class ConstantFormatStructure<in T>(
    val string: String
) : NonConcatenatedFormatStructure<T> {
    override fun toString(): String = "ConstantFormatStructure($string)"

    override fun equals(other: Any?): Boolean = other is ConstantFormatStructure<*> && string == other.string
    override fun hashCode(): Int = string.hashCode()

    override fun parser(): ParserStructure<T> = ParserStructure(
        operations = when {
            string.isEmpty() -> emptyList()
            else -> buildList {
                val suffix = if (string[0].isAsciiDigit()) {
                    add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(string.takeWhile { it.isAsciiDigit() }))))
                    string.dropWhile { it.isAsciiDigit() }
                } else {
                    string
                }
                if (suffix.isNotEmpty()) {
                    if (suffix[suffix.length - 1].isAsciiDigit()) {
                        add(PlainStringParserOperation(suffix.dropLastWhile { it.isAsciiDigit() }))
                        add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(suffix.takeLastWhile { it.isAsciiDigit() }))))
                    } else {
                        add(PlainStringParserOperation(suffix))
                    }
                }
            }
        },
