package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Test that parsing rejects non-ASCII digits.
 *
 * Non-ASCII digits include:
 * - Full-width digits: ０-９ (U+FF10 to U+FF19)
 * - Arabic-Indic digits: ٠-٩ (U+0660 to U+0669)
 * - Devanagari digits: ०-९ (U+0966 to U+096F)
 * - etc.
 */
class NonAsciiDigitTest {

    @Test
    fun testLocalDateParseRejectsFullWidthDigits() {
        // Full-width digits: ０-９
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse("２０２４０９０６", LocalDate.Formats.ISO_BASIC)
        }
        // Mixed ASCII and full-width digits
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse("2０24٠9０६", LocalDate.Formats.ISO_BASIC)
        }
    }

    @Test
    fun testLocalDateParseRejectsArabicIndicDigits() {
        // Arabic-Indic digits: ٠-٩
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse("٢٠٢٤٠٩٠٦", LocalDate.Formats.ISO_BASIC)
        }
    }

    @Test
    fun testLocalDateParseRejectsDevanagariDigits() {
        // Devanagari digits: ०-९
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse("२०२४०९०६", LocalDate.Formats.ISO_BASIC)
        }
    }

    @Test
    fun testLocalDateParseAcceptsAsciiDigits() {
        // ASCII digits should still work
        assertEquals(LocalDate(2024, 9, 6), LocalDate.parse("20240906", LocalDate.Formats.ISO_BASIC))
        assertEquals(LocalDate(2024, 9, 6), LocalDate.parse("2024-09-06", LocalDate.Formats.ISO))
    }

    @Test
    fun testLocalDateTimeParseRejectsNonAsciiDigits() {
        assertFailsWith<IllegalArgumentException> {
            LocalDateTime.parse("２０２４-０９-０６T１２:３０:４５")
        }
    }

    @Test
    fun testLocalTimeParseRejectsNonAsciiDigits() {
        assertFailsWith<IllegalArgumentException> {
            LocalTime.parse("１２:３０:４５")
        }
    }

    @Test
    fun testUtcOffsetParseRejectsNonAsciiDigits() {
        assertFailsWith<IllegalArgumentException> {
            UtcOffset.parse("＋０１:３０")
        }
    }

    @Test
    fun testCustomFormatRejectsNonAsciiDigits() {
        val format = LocalDate.Format {
            year()
            monthNumber()
            dayOfMonth()
        }
        assertFailsWith<IllegalArgumentException> {
            format.parse("２０２４０９０６")
        }
    }

    @Test
    fun testIsoFormatRejectsNonAsciiDigits() {
        // ISO format with full-width digits should fail
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse("２０２４-０９-０６")
        }
    }
}
"}

